  5→/// Settings panel for account, backend URL, audio source selection, and debug controls.
  6→struct SettingsView: View {
  7→    @Binding var backendURL: String
  8→    @Binding var authServerURL: String
  9→    @Binding var selectedMicID: String?
 10→    @State private var backendURLError: String?
 11→    @State private var authServerURLError: String?
 12→    @Binding var encryptionEnabled: Bool
 13→    @Binding var debugEnableMic: Bool
 14→    @Binding var debugEnableSystem: Bool
 15→    let userEmail: String
 16→    let availableMics: [AudioSource]
 17→    let isBackendReachable: Bool
 18→    let bluetoothRoutingConflict: Bool
 19→    let bluetoothRecommendation: String?
 20→    let systemAudioPermitted: Bool
 21→    let recordingState: RecordingUIState
 22→    let diagnostics: CaptureSessionDiagnostics
 23→    let onCheckHealth: () -> Void
 24→    let onGenerateTestTone: () -> Void
 25→    let onSignOut: () -> Void
 26→
 27→    var body: some View {
 28→        Form {
 29→            accountSection
 30→            systemAudioSection
 31→            backendSection
 32→            microphoneSection
 33→            audioFormatSection
 34→            transcriptionSection
 35→            debugSection
 36→        }
 37→        .formStyle(.grouped)
