 43→    private var accountSection: some View {
 44→        Section("Account") {
 45→            LabeledContent("Signed in as", value: userEmail)
 46→
 47→            Button("Sign Out", role: .destructive) {
 48→                onSignOut()
 49→            }
 50→            .buttonStyle(.bordered)
 51→            .controlSize(.small)
