 53→    }
 54→
 55→    private var systemAudioSection: some View {
 56→        Section("System Audio") {
 57→            HStack {
 58→                StatusIndicator(
 59→                    isActive: systemAudioPermitted,
 60→                    activeLabel: "Screen & System Audio Recording: Likely Granted",
 61→                    inactiveLabel: "Screen & System Audio Recording: Not Granted",
 62→                    inactiveColor: .pabloHoney
 63→                )
 64→
 65→                Spacer()
 66→
 67→                Button("Open Settings") {
 68→                    let urlString = "x-apple.systempreferences:com.apple.preference.security?Privacy_ScreenCapture"
