 72→                }
 73→                .buttonStyle(.bordered)
 74→                .controlSize(.small)
 75→            }
 76→
 77→            Text("System audio capture requires \"Screen & System Audio Recording\" permission. "
 78→                + "Enable this app in System Settings > Privacy & Security > Screen & System Audio Recording.")
 79→                .font(.caption)
 80→                .foregroundStyle(systemAudioPermitted ? Color.secondary : Color.pabloHoney)
 81→        }
 82→    }
