 84→    private var backendSection: some View {
 85→        Section("Backend") {
 86→            TextField("Backend URL", text: $backendURL)
 87→                .textFieldStyle(.roundedBorder)
 88→                .onChange(of: backendURL) { _, newValue in
 89→                    backendURLError = URLValidator.validateScheme(newValue)
 90→                }
 91→            if let error = backendURLError {
 92→                ErrorMessageLabel(message: error)
 93→            }
 94→
 95→            TextField("Auth Server URL", text: $authServerURL)
 96→                .textFieldStyle(.roundedBorder)
 97→                .onChange(of: authServerURL) { _, newValue in
 98→                    authServerURLError = URLValidator.validateScheme(newValue)
 99→                }
100→            if let error = authServerURLError {
101→                ErrorMessageLabel(message: error)
102→            }
103→
104→            connectionStatus
105→        }
106→    }
107→
108→    private var connectionStatus: some View {
109→        HStack {
110→            StatusIndicator(
111→                isActive: isBackendReachable,
112→                activeLabel: "Connected",
113→                inactiveLabel: "Not connected"
114→            )
115→
116→            Spacer()
117→
118→            Button("Check", action: onCheckHealth)
119→                .buttonStyle(.bordered)
120→                .controlSize(.small)
121→        }
122→    }
123→
124→    private var microphoneSection: some View {
125→        Section("Microphone") {
126→            if availableMics.isEmpty {
127→                Text("No microphones found")
128→                    .foregroundStyle(.secondary)
