 14→
 15→    var body: some View {
 16→        Group {
 17→            switch authVM.authState {
 18→            case .unauthenticated, .authenticating, .tokenExpired:
 19→                LoginView(authViewModel: authVM)
 20→                    .frame(minWidth: 500, minHeight: 600)
 21→
 22→            case .authenticated:
 23→                authenticatedContent
 24→            }
 25→        }
 26→        .background(Color.pabloCream)
 27→        .preferredColorScheme(.light)
 28→    }
 29→
 30→    private var authenticatedContent: some View {
 31→        TabView(selection: $selectedTab) {
 32→            todayTab
 33→            sessionsTab
 34→            patientsTab
 35→            settingsTab
 36→        }
 37→        .frame(minWidth: 500, minHeight: 600)
 38→        .task { await configureAndLoad() }
 39→        .alert("Recording Error", isPresented: $recordingVM.showError, presenting: recordingVM.errorMessage) { _ in
 40→            Button("OK") {}
 41→        } message: { message in
 42→            Text(message)
 43→        }
 44→        .alert("Upload Error", isPresented: $uploadVM.showError, presenting: uploadVM.errorMessage) { _ in
 45→            Button("OK") {}
 46→        } message: { message in
 47→            Text(message)
 48→        }
 49→        .alert("Patient Error", isPresented: $patientVM.showError, presenting: patientVM.errorMessage) { _ in
 50→            Button("OK") {}
 51→        } message: { message in
 52→            Text(message)
 53→        }
 54→        .alert("Session Error", isPresented: $sessionVM.showError, presenting: sessionVM.errorMessage) { _ in
 55→            Button("OK") {}
 56→        } message: { message in
 57→            Text(message)
 58→        }
 59→        .task {
 60→            while !Task.isCancelled {
 61→                try? await Task.sleep(for: .seconds(300))
 62→                guard !Task.isCancelled else { break }
 63→                await transcriptionVM.retryPendingUploads()
 64→            }
 65→        }
 66→        .sheet(item: $viewingTranscript) { item in
 67→            TranscriptViewerView(transcript: item.text, recordingDate: item.recordingDate)
 68→        }
 69→        .onChange(of: uploadVM.backendURL) { _, newURL in
 70→            patientVM.backendURL = newURL
 71→            sessionVM.backendURL = newURL
 72→        }
 73→    }
