/// Flow:
///   1. `transcribeIfNeeded(_:)` — checks auto-transcribe setting, kicks off pipeline
///   2. Calls pablo-core `transcribeSession1on1` then `renderGoogleMeet`
///   3. Tries to POST the transcript to the backend
///   4. On upload failure: saves encrypted pending file (retry queue)
///   5. `retryPendingUploads()` — called on app launch to flush the queue
@MainActor
@Observable
final class TranscriptionViewModel {
    // MARK: - State

    /// Transcription state keyed by recording ID.
    var states: [UUID: TranscriptionState] = [:]

    /// Number of transcripts waiting to be uploaded.
    var pendingUploadCount = 0

    /// Recordings waiting for a Whisper model download before transcription.
    var awaitingModelRecordings: [LocalRecording] = []

    var errorMessage: String?
    var showError = false

    // MARK: - Dependencies

    var backendURL = "" {
        didSet {
            if URLValidator.validateScheme(backendURL) == nil {
                let token = apiClient.getToken
                apiClient = APIClient(baseURL: backendURL)
                apiClient.getToken = token
            }
        }
    }

    // MARK: - Private

    private var apiClient = APIClient()
    private let store = PendingTranscriptStore()
    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "TranscriptionViewModel")

    private var autoTranscribe: Bool {
        UserDefaults.standard.object(forKey: "autoTranscribe") as? Bool ?? true
    }

    private var qualityPreset: WhisperModelPreset {
        let raw = UserDefaults.standard.string(forKey: "qualityPreset") ?? ""
        return WhisperModelPreset(rawValue: raw) ?? .balanced
    }

    /// Configures the API client with a token provider for authenticated requests.
    func configureAuth(getToken: @escaping @Sendable () async throws -> String) {
        apiClient.getToken = getToken
    }

    // MARK: - Public API

    /// Triggers transcription for a recording if auto-transcribe is enabled.
    func transcribeIfNeeded(_ recording: LocalRecording) {
        guard autoTranscribe else { return }
        guard recording.micPCMFileURL != nil else {
            logger.info("Skipping transcription: no PCM sidecar for \(recording.id)")
            return
        }
        Task { await transcribe(recording) }
    }

    /// Unconditionally runs the full transcription pipeline for a recording.
    func transcribe(_ recording: LocalRecording) async {
        guard let micPath = recording.micPCMFileURL?.path else {
            states[recording.id] = .failed(message: "No mic audio file available")
            return
        }

        states[recording.id] = .running
        logger.info("Starting transcription for \(recording.id)")

        do {
            let config = try buildTranscriptionConfig()
            let result = try await transcribeSession1on1(
                sessionId: recording.id.uuidString,
                micPath: micPath,
                systemPath: recording.systemPCMFileURL?.path,
                config: config
            )
            let text = renderGoogleMeet(transcript: result, opts: renderOptions(for: recording))
            logger.info("Transcription complete for \(recording.id), \(result.segments.count) segments")
            await uploadOrQueue(recording: recording, text: text)
        } catch is ModelError {
            states[recording.id] = .awaitingModel
            awaitingModelRecordings.append(recording)
            logger.info("Transcription deferred for \(recording.id): model not downloaded")
        } catch {
            let message = error.localizedDescription
            states[recording.id] = .failed(message: message)
            logger.error("Transcription failed for \(recording.id): \(message)")
        }
    }

    /// Retry all pending transcripts that failed to upload.
    /// Uses exponential backoff: skips items that have been retried too many times recently.
    /// After 10 retries, stops auto-retrying (manual "Retry Now" still works).
    func retryPendingUploads() async {
        let pending = store.loadAll()
        pendingUploadCount = pending.count
        guard !pending.isEmpty else { return }
        logger.info("Retrying \(pending.count) pending transcript uploads")

        for var item in pending {
            // Exponential backoff: skip items past their retry window
            if item.retryCount > 10 { continue }
            if item.retryCount > 0 {
                let backoffSeconds = min(14400, 300 * Int(pow(2.0, Double(item.retryCount - 1))))
                let elapsed = Date().timeIntervalSince(item.createdAt)
                if elapsed < Double(backoffSeconds) { continue }
            }

            do {
                try await postTranscript(sessionID: item.sessionID, text: item.text)
                store.delete(recordingID: item.recordingID)
                pendingUploadCount = max(0, pendingUploadCount - 1)
                if case let .pendingUpload(text) = states[item.recordingID] {
                    states[item.recordingID] = .done(transcript: text)
                }
                logger.info("Retry upload succeeded for \(item.recordingID)")
            } catch {
                item.retryCount += 1
                store.save(item)
                logger.warning("Retry upload failed for \(item.recordingID): \(error.localizedDescription)")
            }
        }
    }

    /// Force-retry all pending uploads immediately, ignoring backoff. Called by the "Retry Now" button.
    func forceRetryPendingUploads() async {
        let pending = store.loadAll()
        pendingUploadCount = pending.count
        guard !pending.isEmpty else { return }
        logger.info("Force-retrying \(pending.count) pending transcript uploads")

        for var item in pending {
            do {
                try await postTranscript(sessionID: item.sessionID, text: item.text)
                store.delete(recordingID: item.recordingID)
                pendingUploadCount = max(0, pendingUploadCount - 1)
                if case let .pendingUpload(text) = states[item.recordingID] {
                    states[item.recordingID] = .done(transcript: text)
                }
                logger.info("Force retry upload succeeded for \(item.recordingID)")
            } catch {
                item.retryCount += 1
                store.save(item)
                logger.warning("Force retry upload failed for \(item.recordingID): \(error.localizedDescription)")
            }
        }
    }

    /// Process recordings that were deferred because the Whisper model wasn't available.
    /// Called after a model download completes.
    func processAwaitingModelRecordings() async {
        let pending = awaitingModelRecordings
        awaitingModelRecordings.removeAll()
        for recording in pending {
            await transcribe(recording)
        }
    }

    // MARK: - Private

    private func buildTranscriptionConfig() throws -> TranscriptionConfig {
        let modelURL = try ModelManager.shared.modelURL(for: qualityPreset)
        return TranscriptionConfig(
            modelPath: modelURL.path,
            micChannels: 1,
            micSampleRate: 48000,
            systemChannels: 2,
            systemSampleRate: 48000,
            swapSpeakers: UserDefaults.standard.bool(forKey: "swapSpeakers")
        )
    }

    private func renderOptions(for recording: LocalRecording) -> GoogleMeetOptions {
        GoogleMeetOptions(
            sessionDate: recording.createdAt.formatted(date: .long, time: .omitted),
            therapistName: "Therapist",
            clientName: "Client",
            clientAName: "Client A",
            clientBName: "Client B"
        )
    }

    private func uploadOrQueue(recording: LocalRecording, text: String) async {
        do {
            try await postTranscript(sessionID: recording.id.uuidString, text: text)
            states[recording.id] = .done(transcript: text)
            logger.info("Transcript uploaded for \(recording.id)")
        } catch {
            logger.warning("Upload failed, queuing for retry: \(error.localizedDescription)")
            let pending = PendingTranscriptStore.PendingTranscript(
                recordingID: recording.id,
                sessionID: recording.id.uuidString,
                text: text,
                createdAt: Date(),
                retryCount: 0
            )
            store.save(pending)
            states[recording.id] = .pendingUpload(transcript: text)
            pendingUploadCount += 1
        }
    }

    private func postTranscript(sessionID: String, text: String) async throws {
        let response = try await apiClient.uploadTranscript(
            sessionId: sessionID,
            format: "google_meet",
            content: text
        )
        logger.info("Transcript uploaded for session \(sessionID), message: \(response.message)")
    }
}

import SwiftUI

/// Main view — authenticates, then shows four-tab navigation.
struct ContentView: View {
    @State private var authVM = AuthViewModel()
    @State private var sessionVM = SessionViewModel()
    @State private var recordingVM = RecordingViewModel()
    @State private var uploadVM = UploadViewModel()
    @State private var patientVM = PatientViewModel()
    @State private var transcriptionVM = TranscriptionViewModel()
    @State private var viewingTranscript: TranscriptViewerItem?
    @State private var activeSessionId: String?
    @State private var selectedTab = 0

    var body: some View {
        Group {
            switch authVM.authState {
            case .unauthenticated, .authenticating, .tokenExpired:
                LoginView(authViewModel: authVM)
                    .frame(minWidth: 500, minHeight: 600)

            case .authenticated:
                authenticatedContent
            }
        }
        .background(Color.pabloCream)
        .preferredColorScheme(.light)
    }

    private var authenticatedContent: some View {
        TabView(selection: $selectedTab) {
            todayTab
            sessionsTab
            patientsTab
            settingsTab
        }
        .frame(minWidth: 500, minHeight: 600)
        .task { await configureAndLoad() }
        .alert("Recording Error", isPresented: $recordingVM.showError, presenting: recordingVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .alert("Upload Error", isPresented: $uploadVM.showError, presenting: uploadVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .alert("Patient Error", isPresented: $patientVM.showError, presenting: patientVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .alert("Session Error", isPresented: $sessionVM.showError, presenting: sessionVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .task {
            while !Task.isCancelled {
                try? await Task.sleep(for: .seconds(300))
                guard !Task.isCancelled else { break }
                await transcriptionVM.retryPendingUploads()
            }
        }
        .sheet(item: $viewingTranscript) { item in
            TranscriptViewerView(transcript: item.text, recordingDate: item.recordingDate)
        }
        .onChange(of: uploadVM.backendURL) { _, newURL in
            patientVM.backendURL = newURL
            sessionVM.backendURL = newURL
        }
    }

    // MARK: - Setup

    private func configureAndLoad() async {
        let serverURL = KeychainManager.getToken(forKey: .authServerURL)
            ?? authVM.authServerURL
        if let config = try? await fetchServerConfig(authServerURL: serverURL) {
            uploadVM.backendURL = config.apiUrl
            patientVM.backendURL = config.apiUrl
            sessionVM.backendURL = config.apiUrl
            if KeychainManager.getToken(forKey: .firebaseAPIKey) == nil {
                if let key = config.firebaseApiKey, !key.isEmpty {
                    KeychainManager.saveToken(key, forKey: .firebaseAPIKey)
                }
            }
        }

        uploadVM.configureAuth { [authVM] in try await authVM.getValidToken() }
        patientVM.configureAuth { [authVM] in try await authVM.getValidToken() }
        sessionVM.configureAuth { [authVM] in try await authVM.getValidToken() }

        do {
            _ = try await authVM.getValidToken()
        } catch {
            authVM.signOut()
        }

        await sessionVM.loadTodaySessions()
        await patientVM.loadPatients()
        await recordingVM.loadAudioSources()
        await uploadVM.checkBackendHealth()

        transcriptionVM.backendURL = uploadVM.backendURL
        transcriptionVM.configureAuth { [authVM] in try await authVM.getValidToken() }
        await transcriptionVM.retryPendingUploads()

        recordingVM.onRecordingCompleted = { [transcriptionVM] recording in
            transcriptionVM.transcribeIfNeeded(recording)
        }

        ModelManager.shared.onModelDownloaded = { [transcriptionVM] _ in
            Task { await transcriptionVM.processAwaitingModelRecordings() }
        }
    }

    // MARK: - Session orchestration

    private func startSession(_ session: Session) {
        Task {
            guard await sessionVM.startSession(session.id) != nil else { return }
            activeSessionId = session.id
            await recordingVM.startRecording()
            VideoLaunchService.launch(session: session)
        }
    }

    private func handleQuickStart(_ patient: Patient) {
        Task {
            guard let session = await sessionVM.createAdHocSession(patientId: patient.id) else { return }
            guard await sessionVM.startSession(session.id) != nil else { return }
            activeSessionId = session.id
            await recordingVM.startRecording()
        }
    }

    // MARK: - Tabs

    private var todayTab: some View {
        DayView(
            sessionVM: sessionVM,
            patients: patientVM.patients,
            isLoadingPatients: patientVM.isLoading,
            patientSearchText: $patientVM.searchText,
            recordingState: recordingVM.recordingState,
            recordingDuration: recordingVM.duration,
            pendingUploadCount: transcriptionVM.pendingUploadCount,
            awaitingModelCount: transcriptionVM.awaitingModelRecordings.count,
            onStartSession: { startSession($0) },
            onQuickStart: { handleQuickStart($0) },
            onStopRecording: {
                Task {
                    await recordingVM.stopRecording()
                    if let sessionId = activeSessionId {
                        _ = await sessionVM.endSession(sessionId)
                        activeSessionId = nil
                    }
                    await sessionVM.loadTodaySessions()
                }
            },
            onRetryUploads: { Task { await transcriptionVM.forceRetryPendingUploads() } },
            onSwitchToSettings: { selectedTab = 3 }
        )
        .tabItem { Label("Today", systemImage: "calendar") }
        .tag(0)
    }

    private var sessionsTab: some View {
        SessionHistoryView(
            viewModel: sessionVM,
            patients: patientVM.patients,
            pendingUploadCount: transcriptionVM.pendingUploadCount,
            onRetryUploads: { Task { await transcriptionVM.forceRetryPendingUploads() } }
        )
        .tabItem { Label("Sessions", systemImage: "list.clipboard") }
        .tag(1)
    }

    private var patientsTab: some View {
        PatientListView(viewModel: patientVM)
            .tabItem { Label("Patients", systemImage: "person.2") }
            .tag(2)
    }

    private var settingsTab: some View {
        SettingsView(
            backendURL: $uploadVM.backendURL,
            authServerURL: $authVM.authServerURL,
            selectedMicID: $recordingVM.selectedMicID,
            encryptionEnabled: $recordingVM.encryptionEnabled,
            debugEnableMic: $recordingVM.debugEnableMic,
            debugEnableSystem: $recordingVM.debugEnableSystem,
            userEmail: authVM.authenticatedEmail,
            availableMics: recordingVM.availableMics,
            isBackendReachable: uploadVM.isBackendReachable,
            bluetoothRoutingConflict: recordingVM.bluetoothRoutingConflict,
            bluetoothRecommendation: recordingVM.bluetoothRecommendation,
            systemAudioPermitted: recordingVM.systemAudioPermitted,
            recordingState: recordingVM.recordingState,
            diagnostics: recordingVM.debugDiagnostics,
            onCheckHealth: { Task { await uploadVM.checkBackendHealth() } },
            onGenerateTestTone: { recordingVM.generateTestTone() },
            onSignOut: { authVM.signOut() }
        )
        .tabItem { Label("Settings", systemImage: "gear") }
        .tag(3)
    }
}

import Foundation
import os

// MARK: - DisplaySessionType

/// UI-facing session type for display in Settings. Distinct from the UniFFI-generated
/// ``SessionType`` enum used in the API layer.
enum DisplaySessionType: String, CaseIterable, Sendable {
    case oneToOne = "1:1"
    case couples = "Couples"

    var displayName: String {
        rawValue
    }
}

// MARK: - WhisperModelPreset

/// Local Whisper model quality tier. Distinct from the UniFFI-generated
/// ``QualityPreset`` enum used in the API layer (user preferences).
enum WhisperModelPreset: String, CaseIterable, Sendable {
    case fast // whisper-small (~200 MB)
    case balanced // whisper-large-v3-turbo Q5_0 (~1.0 GB) — default
    case highAccuracy // whisper-large-v3 (~1.6 GB) — on-demand download

    var modelFileName: String {
        switch self {
        case .fast: "ggml-small.bin"
        case .balanced: "ggml-large-v3-turbo-q5_0.bin"
        case .highAccuracy: "ggml-large-v3.bin"
        }
    }

    var displayName: String {
        switch self {
        case .fast: "Fast"
        case .balanced: "Balanced"
        case .highAccuracy: "High Accuracy"
        }
    }

    var diskSizeDescription: String {
        switch self {
        case .fast: "~200 MB"
        case .balanced: "~1.0 GB"
        case .highAccuracy: "~1.6 GB"
        }
    }
}

// MARK: - ModelError

enum ModelError: Error, LocalizedError {
    case notFound(WhisperModelPreset)
    case downloadFailed(String)

    var errorDescription: String? {
        switch self {
        case let .notFound(preset):
            "Model file not found for \(preset.displayName) preset (\(preset.modelFileName))"
        case let .downloadFailed(reason):
            "Model download failed: \(reason)"
        }
    }
}

// MARK: - ModelManager

/// Manages Whisper model files for local transcription.
/// Resolves model paths from the app's Application Support directory or the app bundle.
@MainActor
final class ModelManager: ObservableObject {
    static let shared = ModelManager()

    @Published var downloadProgress: [WhisperModelPreset: Double] = [:]
    @Published var downloadingPresets: Set<WhisperModelPreset> = []

    /// Called after a model download completes successfully.
    var onModelDownloaded: ((WhisperModelPreset) -> Void)?

    private let fileManager = FileManager.default
    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "ModelManager")

    private var modelsDirectory: URL {
        let appSupport = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
        let dir = appSupport
            .appendingPathComponent("PabloCompanion", isDirectory: true)
            .appendingPathComponent("Models", isDirectory: true)
        try? fileManager.createDirectory(at: dir, withIntermediateDirectories: true)
        return dir
    }

    /// Returns the URL to the model file for the given preset.
    /// Checks the models directory first, then the app bundle.
    func modelURL(for preset: WhisperModelPreset) throws -> URL {
        // Check Application Support models directory first
        let cachedURL = modelsDirectory.appendingPathComponent(preset.modelFileName)
        if fileManager.fileExists(atPath: cachedURL.path) {
            logger.debug("Found model in cache: \(preset.modelFileName)")
            return cachedURL
        }

        // Fall back to app bundle
        let name = (preset.modelFileName as NSString).deletingPathExtension
        let ext = (preset.modelFileName as NSString).pathExtension
        if let bundledURL = Bundle.main.url(forResource: name, withExtension: ext) {
            logger.debug("Found model in bundle: \(preset.modelFileName)")
            return bundledURL
        }

        logger.warning("Model not found: \(preset.modelFileName)")
        throw ModelError.notFound(preset)
    }

    /// Whether the model for this preset is available (cached or bundled).
    func isAvailable(_ preset: WhisperModelPreset) -> Bool {
        (try? modelURL(for: preset)) != nil
    }

    /// Downloads the model for the given preset from the Hugging Face whisper.cpp repository.
    /// Progress is published via `downloadProgress` and `downloadingPresets`.
    func downloadModel(_ preset: WhisperModelPreset) async throws {
        guard !downloadingPresets.contains(preset) else { return }

        let baseURL = "https://huggingface.co/ggerganov/whisper.cpp/resolve/main/"
        guard let url = URL(string: baseURL + preset.modelFileName) else { return }

        downloadingPresets.insert(preset)
        downloadProgress[preset] = 0
        defer {
            downloadingPresets.remove(preset)
            downloadProgress.removeValue(forKey: preset)
        }

        let destination = modelsDirectory.appendingPathComponent(preset.modelFileName)

        do {
            try await performDownload(from: url, to: destination, preset: preset)
            logger.info("Model downloaded: \(preset.modelFileName)")
            onModelDownloaded?(preset)
        } catch {
            logger.error("Model download failed for \(preset.modelFileName): \(error.localizedDescription)")
            throw ModelError.downloadFailed(error.localizedDescription)
        }
    }

    /// Performs the actual download using a delegate-based URLSession wrapped in a continuation.
    /// Using a dedicated session (not URLSession.shared) ensures progress delegate callbacks fire.
    private nonisolated func performDownload(
        from url: URL,
        to destination: URL,
        preset: WhisperModelPreset
    ) async throws {
        try await withCheckedThrowingContinuation { (continuation: CheckedContinuation<Void, Error>) in
            let delegate = ModelDownloadDelegate(
                destination: destination,
                onProgress: { [weak self] fraction in
                    Task { @MainActor [weak self] in
                        self?.downloadProgress[preset] = fraction
                    }
                },
                onComplete: { error in
                    if let error {
                        continuation.resume(throwing: error)
                    } else {
                        continuation.resume()
                    }
                }
            )
            let session = URLSession(configuration: .default, delegate: delegate, delegateQueue: nil)
            session.downloadTask(with: url).resume()
        }
    }
}

// MARK: - ModelDownloadDelegate

/// Session-level delegate for model downloads. Handles progress reporting, file
/// moves (must happen inside `didFinishDownloadingTo` before the temp file is deleted),
/// and error handling. The URLSession retains this delegate strongly.
private final class ModelDownloadDelegate: NSObject, URLSessionDownloadDelegate, @unchecked Sendable {
    private let destination: URL
    private let onProgress: (Double) -> Void
    private let onComplete: (Error?) -> Void
    private var didFinish = false

    init(
        destination: URL,
        onProgress: @escaping (Double) -> Void,
        onComplete: @escaping (Error?) -> Void
    ) {
        self.destination = destination
        self.onProgress = onProgress
        self.onComplete = onComplete
    }

    func urlSession(
        _ session: URLSession,
        downloadTask _: URLSessionDownloadTask,
        didFinishDownloadingTo location: URL
    ) {
        guard !didFinish else { return }
        didFinish = true
        do {
            let fm = FileManager.default
            if fm.fileExists(atPath: destination.path) {
                try fm.removeItem(at: destination)
            }
            try fm.moveItem(at: location, to: destination)
            session.finishTasksAndInvalidate()
            onComplete(nil)
        } catch {
            session.invalidateAndCancel()
            onComplete(error)
        }
    }

    func urlSession(
        _ session: URLSession,
        task _: URLSessionTask,
        didCompleteWithError error: Error?
    ) {
        guard !didFinish, let error else { return }
        didFinish = true
        session.invalidateAndCancel()
        onComplete(error)
    }

    func urlSession(
        _: URLSession,
        downloadTask _: URLSessionDownloadTask,
        didWriteData _: Int64,
        totalBytesWritten: Int64,
        totalBytesExpectedToWrite: Int64
    ) {
        guard totalBytesExpectedToWrite > 0 else { return }
        onProgress(Double(totalBytesWritten) / Double(totalBytesExpectedToWrite))
    }
}

