273→    private func pollSessions() async {
274→        while !Task.isCancelled {
275→            try? await Task.sleep(for: .seconds(30))
276→            guard !Task.isCancelled else { break }
277→            guard recordingState == .idle else { continue }
278→            await sessionVM.loadTodaySessions()
279→            lastRefreshDate = Date()
280→        }
281→    }
