291→    private var greeting: String {
292→        let hour = Calendar.current.component(.hour, from: Date())
293→        switch hour {
294→        case 0 ..< 12: return "Good morning"
295→        case 12 ..< 17: return "Good afternoon"
296→        default: return "Good evening"
297→        }
298→    }
