 33→            Circle()
 34→                .fill(avatarColor.opacity(0.18))
 35→                .frame(width: 36, height: 36)
 36→                .overlay {
 37→                    Circle()
 38→                        .stroke(Color.pabloSage, lineWidth: 2)
 39→                        .opacity(isPulsing ? 0.35 : 0.18)
 40→                        .animation(pulseAnimation, value: isPulsing)
 41→                        .opacity(session.status == .inProgress ? 1 : 0)
 42→                }
 43→            Text(initials)
 44→                .font(.system(size: 14, weight: .semibold))
 45→                .foregroundStyle(Color.pabloBrownDeep)
