  4→// MARK: - TranscriptionState
  5→
  6→enum TranscriptionState: Sendable {
  7→    case running
  8→    case done(transcript: String)
  9→    case pendingUpload(transcript: String)
 10→    case awaitingModel
 11→    case failed(message: String)
 12→
 13→    var transcript: String? {
 14→        switch self {
 15→        case let .done(text), let .pendingUpload(text): text
 16→        default: nil
 17→        }
 18→    }
 19→
 20→    var isPendingUpload: Bool {
 21→        if case .pendingUpload = self { return true }
 22→        return false
 23→    }
 24→}
 25→
 26→// MARK: - TranscriptionViewModel
 27→
 28→/// Orchestrates the local transcription pipeline after a session ends.
 29→///
 30→/// Flow:
 31→///   1. `transcribeIfNeeded(_:)` — checks auto-transcribe setting, kicks off pipeline
 32→///   2. Calls pablo-core `transcribeSession1on1` then `renderGoogleMeet`
 33→///   3. Tries to POST the transcript to the backend
 34→///   4. On upload failure: saves encrypted pending file (retry queue)
 35→///   5. `retryPendingUploads()` — called on app launch to flush the queue
 36→@MainActor
 37→@Observable
 38→final class TranscriptionViewModel {
 39→    // MARK: - State
 40→
 41→    /// Transcription state keyed by recording ID.
 42→    var states: [UUID: TranscriptionState] = [:]
 43→
 44→    /// Number of transcripts waiting to be uploaded.
 45→    var pendingUploadCount = 0
 46→
 47→    /// Recordings waiting for a Whisper model download before transcription.
 48→    var awaitingModelRecordings: [LocalRecording] = []
 49→
 50→    /// Count derived from actual states — avoids stale banner when state transitions happen.
 51→    var awaitingModelCount: Int {
 52→        states.values.count(where: {
 53→            if case .awaitingModel = $0 { return true }
 54→            return false
 55→        })
 56→    }
 57→
 58→    var errorMessage: String?
 59→    var showError = false
 60→
 61→    // MARK: - Dependencies
 62→
 63→    var backendURL = "" {
 64→        didSet {
 65→            if URLValidator.validateScheme(backendURL) == nil {
 66→                let token = apiClient.getToken
 67→                apiClient = APIClient(baseURL: backendURL)
 68→                apiClient.getToken = token
 69→            }
 70→        }
 71→    }
 72→
 73→    // MARK: - Private
 74→
 75→    private var apiClient = APIClient()
 76→    private let store = PendingTranscriptStore()
 77→    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "TranscriptionViewModel")
 78→
 79→    private var autoTranscribe: Bool {
 80→        UserDefaults.standard.object(forKey: "autoTranscribe") as? Bool ?? true
 81→    }
 82→
 83→    private var qualityPreset: WhisperModelPreset {
 84→        let raw = UserDefaults.standard.string(forKey: "qualityPreset") ?? ""
 85→        return WhisperModelPreset(rawValue: raw) ?? .balanced
 86→    }
 87→
 88→    /// Configures the API client with a token provider for authenticated requests.
 89→    func configureAuth(getToken: @escaping @Sendable () async throws -> String) {
 90→        apiClient.getToken = getToken
 91→    }
 92→
 93→    // MARK: - Public API
 94→
 95→    /// Triggers transcription for a recording if auto-transcribe is enabled.
 96→    func transcribeIfNeeded(_ recording: LocalRecording) {
 97→        guard autoTranscribe else { return }
 98→        guard recording.micPCMFileURL != nil else {
 99→            logger.info("Skipping transcription: no PCM sidecar for \(recording.id)")
100→            return
101→        }
102→        Task { await transcribe(recording) }
103→    }
104→
105→    /// Unconditionally runs the full transcription pipeline for a recording.
106→    /// - Parameter presetOverride: If provided, uses this model preset instead of the user's configured quality preset.
107→    func transcribe(_ recording: LocalRecording, using presetOverride: WhisperModelPreset? = nil) async {
108→        guard let micPath = recording.micPCMFileURL?.path else {
109→            states[recording.id] = .failed(message: "No mic audio file available")
110→            return
111→        }
112→
113→        states[recording.id] = .running
114→        logger.info("Starting transcription for \(recording.id)")
115→
116→        do {
117→            let config = try buildTranscriptionConfig(using: presetOverride)
118→            let result = try await transcribeSession1on1(
119→                sessionId: recording.id.uuidString,
120→                micPath: micPath,
121→                systemPath: recording.systemPCMFileURL?.path,
122→                config: config
123→            )
124→            let text = renderGoogleMeet(transcript: result, opts: renderOptions(for: recording))
125→            logger.info("Transcription complete for \(recording.id), \(result.segments.count) segments")
126→            await uploadOrQueue(recording: recording, text: text)
127→        } catch is ModelError {
128→            states[recording.id] = .awaitingModel
129→            awaitingModelRecordings.append(recording)
130→            logger.info("Transcription deferred for \(recording.id): model not downloaded")
131→        } catch {
132→            let message = error.localizedDescription
133→            states[recording.id] = .failed(message: message)
134→            logger.error("Transcription failed for \(recording.id): \(message)")
135→        }
136→    }
137→
138→    /// Retry all pending transcripts that failed to upload.
139→    /// Uses exponential backoff: skips items that have been retried too many times recently.
140→    /// After 10 retries, stops auto-retrying (manual "Retry Now" still works).
141→    func retryPendingUploads() async {
142→        let pending = store.loadAll()
143→        pendingUploadCount = pending.count
144→        guard !pending.isEmpty else { return }
145→        logger.info("Retrying \(pending.count) pending transcript uploads")
146→
147→        for var item in pending {
148→            // Exponential backoff: skip items past their retry window
149→            if item.retryCount > 10 { continue }
150→            if item.retryCount > 0 {
151→                let backoffSeconds = min(14400, 300 * Int(pow(2.0, Double(item.retryCount - 1))))
152→                let elapsed = Date().timeIntervalSince(item.createdAt)
153→                if elapsed < Double(backoffSeconds) { continue }
154→            }
155→
156→            do {
157→                try await postTranscript(sessionID: item.sessionID, text: item.text)
158→                store.delete(recordingID: item.recordingID)
159→                pendingUploadCount = max(0, pendingUploadCount - 1)
160→                if case let .pendingUpload(text) = states[item.recordingID] {
161→                    states[item.recordingID] = .done(transcript: text)
162→                }
163→                logger.info("Retry upload succeeded for \(item.recordingID)")
164→            } catch {
165→                item.retryCount += 1
166→                store.save(item)
167→                logger.warning("Retry upload failed for \(item.recordingID): \(error.localizedDescription)")
168→            }
169→        }
170→    }
171→
172→    /// Force-retry all pending uploads immediately, ignoring backoff. Called by the "Retry Now" button.
173→    func forceRetryPendingUploads() async {
174→        let pending = store.loadAll()
175→        pendingUploadCount = pending.count
176→        guard !pending.isEmpty else { return }
177→        logger.info("Force-retrying \(pending.count) pending transcript uploads")
178→
179→        for var item in pending {
180→            do {
181→                try await postTranscript(sessionID: item.sessionID, text: item.text)
182→                store.delete(recordingID: item.recordingID)
183→                pendingUploadCount = max(0, pendingUploadCount - 1)
184→                if case let .pendingUpload(text) = states[item.recordingID] {
185→                    states[item.recordingID] = .done(transcript: text)
186→                }
187→                logger.info("Force retry upload succeeded for \(item.recordingID)")
188→            } catch {
189→                item.retryCount += 1
190→                store.save(item)
191→                logger.warning("Force retry upload failed for \(item.recordingID): \(error.localizedDescription)")
192→            }
193→        }
194→    }
195→
196→    /// Process recordings that were deferred because the Whisper model wasn't available.
197→    /// Called after a model download completes. Uses the just-downloaded preset so we
198→    /// don't fail again looking for a different model than what the user downloaded.
199→    func processAwaitingModelRecordings(downloadedPreset: WhisperModelPreset) async {
200→        let pending = awaitingModelRecordings
201→        awaitingModelRecordings.removeAll()
202→        for recording in pending {
203→            await transcribe(recording, using: downloadedPreset)
204→        }
205→    }
206→
207→    // MARK: - Private
208→
209→    private func buildTranscriptionConfig(
210→        using presetOverride: WhisperModelPreset? = nil
211→    ) throws -> TranscriptionConfig {
212→        let preset = presetOverride ?? qualityPreset
213→        let modelURL = try ModelManager.shared.modelURL(for: preset)
214→        return TranscriptionConfig(
215→            modelPath: modelURL.path,
216→            micChannels: 1,
217→            micSampleRate: 48000,
218→            systemChannels: 2,
219→            systemSampleRate: 48000,
220→            swapSpeakers: UserDefaults.standard.bool(forKey: "swapSpeakers")
221→        )
222→    }
223→
224→    private func renderOptions(for recording: LocalRecording) -> GoogleMeetOptions {
225→        GoogleMeetOptions(
226→            sessionDate: recording.createdAt.formatted(date: .long, time: .omitted),
227→            therapistName: "Therapist",
228→            clientName: "Client",
229→            clientAName: "Client A",
230→            clientBName: "Client B"
231→        )
232→    }
233→
234→    private func uploadOrQueue(recording: LocalRecording, text: String) async {
235→        do {
236→            try await postTranscript(sessionID: recording.id.uuidString, text: text)
237→            states[recording.id] = .done(transcript: text)
238→            logger.info("Transcript uploaded for \(recording.id)")
239→        } catch {
240→            logger.warning("Upload failed, queuing for retry: \(error.localizedDescription)")
241→            let pending = PendingTranscriptStore.PendingTranscript(
242→                recordingID: recording.id,
243→                sessionID: recording.id.uuidString,
244→                text: text,
245→                createdAt: Date(),
246→                retryCount: 0
247→            )
248→            store.save(pending)
249→            states[recording.id] = .pendingUpload(transcript: text)
250→            pendingUploadCount += 1
251→        }
252→    }
253→
254→    private func postTranscript(sessionID: String, text: String) async throws {
255→        let response = try await apiClient.uploadTranscript(
256→            sessionId: sessionID,
257→            format: "google_meet",
258→            content: text
259→        )
260→        logger.info("Transcript uploaded for session \(sessionID), message: \(response.message)")
261→    }
262→}
